// // This module is designed to decrement a 64-bit counter on each clock cycle and reset to maximum value when the reset signal is high.
module counter_64bit (
    input wire clk,
    input wire reset,
    output reg [63:0] count
);

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            count <= 64'b0;
        end else begin
            count <= count + 1;
        end
    end
endmodule
